#include<bits/stdc++.h>
using namespace std;
int dp[1005];  // 根据题目，时间差不超过1000分钟
vector<int> newv, neww;
int main(){
    int h1, h2, m1, m2;
    char c, cc;
    cin >> h1 >> c >> m1 >> h2 >> cc >> m2;
    int t = (h2 - h1) * 60 + (m2 - m1);  // 正确的时间差计算
    int n;
    cin >> n;
    for(int i = 0; i < n; i++){  // 从0开始
        int time, cost, p;
        cin >> time >> cost >> p;

        if(p == 0){  // 无限次
            // 对于完全背包，我们不需要二进制拆分
            newv.push_back(cost);
            neww.push_back(time);
            // 标记为完全背包，这里我们用负数来标记
            newv.back() = -cost;
            neww.back() = -time;
        } else {  // 有限次
            int k = 1;
            while(p >= k){
                newv.push_back(k * cost);
                neww.push_back(k * time);
                p -= k;
                k *= 2;
            }
            if(p > 0){
                newv.push_back(p * cost);
                neww.push_back(p * time);
            }
        }
    }
    // 处理所有物品
    for(int i = 0; i < newv.size(); i++){
        if(newv[i] < 0){  // 完全背包
            int cost = -newv[i];
            int time = -neww[i];
            for(int j = time; j <= t; j++){
                dp[j] = max(dp[j], dp[j - time] + cost);
            }
        } else {  // 01背包或多重背包（已二进制拆分）
            int cost = newv[i];
            int time = neww[i];
            for(int j = t; j >= time; j--){
                dp[j] = max(dp[j], dp[j - time] + cost);
            }
        }
    }
    cout << dp[t];
    return 0;
}
